package main

import "fmt"

func factorialRecursive(n int) int {
	if n <= 1 {
		return 1
	}
	return n * factorialRecursive(n-1)
}

func factorialIterative(n int) int {
	result := 1
	for i := 2; i <= n; i++ {
		result *= i
	}
	return result
}

func main() {
	fmt.Println("Faktoriyel tablosu (0-10):")
	for i := 0; i <= 10; i++ {
		fmt.Println(i, "! =", factorialIterative(i))
	}

	fmt.Println("\nRecursive 5! =", factorialRecursive(5))
	fmt.Println("Iteratif 5! =", factorialIterative(5))

	// Kombinasyon hesaplama: C(n,r) = n! / (r! * (n-r)!)
	n, r := 5, 2
	combination := factorialIterative(n) / (factorialIterative(r) * factorialIterative(n-r))
	fmt.Printf("\nC(%d,%d) = %d\n", n, r, combination)
}
